import heapq

def solve(grid: list[list[int]], k: int) -> int:
    m = len(grid)
    n = len(grid[0])
    teleport = [[[] for _ in range(n)] for _ in range(m)]
    for i in range(m):
        for j in range(n):
            val = grid[i][j]
            for x in range(m):
                for y in range(n):
                    if grid[x][y] <= val:
                        teleport[i][j].append((x, y))
    INF = float('inf')
    dist = [[[INF] * (k + 1) for _ in range(n)] for _ in range(m)]
    dist[0][0][0] = 0
    heap = []
    heapq.heappush(heap, (0, 0, 0, 0))
    directions = [(0, 1), (1, 0)]
    while heap:
        cost, i, j, t = heapq.heappop(heap)
        if i == m - 1 and j == n - 1:
            return cost
        if cost > dist[i][j][t]:
            continue
        for dx, dy in directions:
            ni, nj = i + dx, j + dy
            if 0 <= ni < m and 0 <= nj < n:
                new_cost = cost + grid[ni][nj]
                if new_cost < dist[ni][nj][t]:
                    dist[ni][nj][t] = new_cost
                    heapq.heappush(heap, (new_cost, ni, nj, t))
        if t < k:
            for x, y in teleport[i][j]:
                new_cost = cost
                if new_cost < dist[x][y][t + 1]:
                    dist[x][y][t + 1] = new_cost
                    heapq.heappush(heap, (new_cost, x, y, t + 1))
    return -1
